function test_after_construct($exchange, $skipped_properties) {
    if (!(is_array($skipped_properties) && array_key_exists('networks', $skipped_properties))) {
        test_options_networks($exchange, $skipped_properties);
    }
    return true;
}


function test_options_networks($exchange, $skipped_properties) {
    if (!(is_array($skipped_properties) && array_key_exists('networks', $skipped_properties))) {
        // only allow these whitelisted unified networkCodes to be repeated
        $allowed_unified_aliases = ['BTC', 'ERC20', 'ETH', 'TRX', 'TRC20', 'BRC20', 'CRONOS', 'CRC20', 'CRO', 'BEP20', 'BSC', 'HECO', 'HRC20', 'HT', 'OP', 'OPTIMISM', 'SPL', 'SOL', 'POLYGON', 'MATIC', 'CARDANO', 'ADA'];
        $networks = $exchange->options['networks'];
        if ($networks === null) {
            return;
        }
        // 1) ensure 'networks' dictionary exists in options
        assert($exchange->is_dictionary($networks), 'exchange.options["networks"] is not a dict');
        if (count(is_array($networks) ? array_keys($networks) : array()) === 0) {
            return;
        }
        // 2) ensure 'networksById' dictionary exists in options
        assert(is_array($exchange->options) && array_key_exists('networksById', $exchange->options), 'exchange.options["networksById"] is not set');
        assert($exchange->is_dictionary($exchange->options['networksById']), 'exchange.options["networksById"] is not a dict');
        //
        $network_codes = is_array($exchange->options['networks']) ? array_keys($exchange->options['networks']) : array();
        // 3) ensure that the same network-id is not assigned to multiple networkCodes
        $collected_network_ids = [];
        for ($i = 0; $i < count($network_codes); $i++) {
            $network_code = $network_codes[$i];
            $network_id = $exchange->options['networks'][$network_code];
            if (!$exchange->in_array($network_code, $allowed_unified_aliases)) {
                assert(!$exchange->in_array($network_id, $collected_network_ids), 'exchange.options["networks"] should not contain multiple non-unified networkCodes (in the list of unified-networks) with the same networkId: "' . $network_id . '"');
            }
            $collected_network_ids[] = $network_id;
        }
        // 4) ensure that there are no same networkCode with different case (uppercase/lowercase)
        $collected_network_codes = [];
        for ($i = 0; $i < count($network_codes); $i++) {
            $network_code_lower = strtolower(($network_codes[$i]));
            assert(!$exchange->in_array($network_code_lower, $collected_network_codes), 'exchange.options["networks"] contains multiple networkCodes with the same networkCode "' . $network_codes[$i] . '" in different uppercase/lowercase format');
            $collected_network_codes[] = $network_code_lower;
        }
        // 5) test networkCodeToId & networkIdToCode
        for ($i = 0; $i < count($network_codes); $i++) {
            $network_code = $network_codes[$i];
            $network_id = $exchange->options['networks'][$network_code];
            // check networkCodeToId
            $network_id_converted = $exchange->network_code_to_id($network_code);
            assert($network_id === $network_id_converted, 'exchange.networkCodeToId ("' . $network_code . '")="' . $network_id_converted . '" does not match exchange.options["networks"]["' . $network_code . '"]="' . $network_id . '"');
            // ensure it exists in networksById
            assert(is_array($exchange->options['networksById']) && array_key_exists($network_id, $exchange->options['networksById']), 'exchange.options["networksById"] does not contain networkId "' . $network_id . '"');
            // ensure networkCode matches for networksById (however, it only works if one mapping is set)
            if (!$exchange->in_array($network_code, $allowed_unified_aliases)) {
                assert($exchange->options['networksById'][$network_id] === $network_code, 'exchange.options["networksById"]["' . $network_id . '"] value is not expected "' . $network_code . '", but: "' . $exchange->options['networksById'][$network_id] . '"');
                // check networkIdToCode conversion back
                $network_code_converted = $exchange->network_id_to_code($network_id);
                assert($network_code === $network_code_converted, 'exchange.networkIdToCode ("' . $network_id . '")="' . $network_code_converted . '" does not match key "' . $network_code . '" of exchange.options["networks"]');
            }
        }
    }
}
